mapper.select:
SELECT t0.*, t1.channel_name FROM article t0
LEFT JOIN channel t1 ON t0.channel_id = t1.channel_id AND t1.deleted = 0
WHERE t0.deleted = 0 AND t0.status = 1
AND t0.channel_id = #{channelId}
AND t0.article_id != #{articleId}
ORDER BY t0.article_id DESC
LIMIT #{limit}

SELECT * FROM article
WHERE deleted = 0 AND status = 1 AND article_id < #{articleId}
ORDER BY article_id DESC LIMIT 1

SELECT * FROM article
WHERE deleted = 0 AND status = 1 AND article_id > #{articleId}
ORDER BY article_id ASC LIMIT 1

SELECT t0.*, t1.channel_name FROM article t0
LEFT JOIN channel t1 ON t0.channel_id = t1.channel_id AND t1.deleted = 0
WHERE t0.deleted = 0
 AND t0.article_id = #{articleId} 
 AND t0.title LIKE CONCAT('%', #{title}, '%') 
 AND t0.create_user_id = #{createUserId} 
 AND t0.channel_id = #{channelId} 
 AND t0.status = #{status} 
ORDER BY t0.is_top DESC, t0.article_id DESC
LIMIT #{page}, #{limit}

SELECT COUNT(1) FROM article t0
WHERE t0.deleted = 0
 AND t0.article_id = #{articleId} 
 AND t0.title LIKE CONCAT('%', #{title}, '%') 
 AND t0.create_user_id = #{createUserId} 
 AND t0.channel_id = #{channelId} 
 AND t0.status = #{status}
